import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";
const PERFORMANCE_API_BASE = "http://localhost:5130"; // this is my demo api just retun demo fake data
// Create server instance
const server = new McpServer({
    name: "performance",
    version: "1.0.0",
});
async function makePerformanceRequest(url) {
    try {
        const response = await fetch(url);
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        return (await response.json());
    }
    catch (error) {
        console.error("Error making performance request:", error);
        return null;
    }
}
// Register demo user tools
server.tool("get-demo-user-list", "get demo user data list", {
    userName: z.string().optional().describe("user name"),
    typeName: z.string().optional().describe("user type"),
}, async ({ userName, typeName }) => {
    let url = `${PERFORMANCE_API_BASE}/Performance`;
    if (userName || typeName) {
        const params = {};
        if (userName)
            params.userName = userName;
        if (typeName)
            params.typeName = typeName;
        const query = new URLSearchParams(params).toString();
        url += `?${query}`;
    }
    const data = await makePerformanceRequest(url);
    if (!data) {
        return {
            content: [
                {
                    type: "text",
                    text: "Failed to retrieve user data",
                },
            ],
        };
    }
    const formattedData = data.map((item) => [
        `Order ID: ${item.orderId}`,
        `User Name: ${item.userName}`,
        `Type Name: ${item.typeName}`,
        `Amount: ${item.amount}`,
        "---",
    ].join("\n"));
    const resultText = `user Data:\n\n${formattedData.join("\n")}`;
    return {
        content: [
            {
                type: "text",
                text: resultText,
            },
        ],
    };
});
async function main() {
    const transport = new StdioServerTransport();
    await server.connect(transport);
    console.error("Demo User MCP Server running on stdio");
}
main().catch((error) => {
    console.error("Fatal error in main():", error);
    process.exit(1);
});

```

